  "suction-cups": {"id":21,"name":"suction-cups","effect":"This Pokémon cannot be forced out of battle by moves such as Whirlwind.\n\nDragon Tail and Circle Throw still inflict damage against this Pokémon.\n\nOverworld: If the lead Pokémon has this ability, the success rate while fishing is increased.","shortEffect":"Prevents being forced out of battle by other Pokémon's moves.","flavorText":"Firmly anchors the body.","gen12Pokemon":[{"id":224,"name":"octillery","isHidden":false,"slot":1}],"isMainSeries":true,"generation":"generation-iii"},
