  "effect-spore": {"id":27,"name":"effect-spore","effect":"Whenever a move makes contact with this Pokémon, the move's user has a 30% chance of being paralyzed, poisoned, or put to sleep, chosen at random.\n\nNothing is done to compensate if the move's user is immune to one of these ailments; there is simply a lower chance that the move's user will be affected.","shortEffect":"Has a 30% chance of inflcting either paralysis, poison, or sleep on attacking Pokémon on contact.","flavorText":"Leaves spores on contact.","gen12Pokemon":[{"id":45,"name":"vileplume","isHidden":true,"slot":3},{"id":46,"name":"paras","isHidden":false,"slot":1},{"id":47,"name":"parasect","isHidden":false,"slot":1}],"isMainSeries":true,"generation":"generation-iii"},
  "synchronize": {"id":28,"name":"synchronize","effect":"Whenever this Pokémon is burned, paralyzed, or poisoned, the Pokémon who gave this Pokémon that ailment is also given the ailment.\n\nThis ability passes back bad poison when this Pokémon is badly poisoned.  This ability cannot pass on a status ailment that the Pokémon did not directly receive from another Pokémon, such as the poison from Toxic Spikes or the burn from a Flame Orb.\n\nOverworld: If the lead Pokémon has this ability, wild Pokémon have a 50% chance of having the lead Pokémon's nature, and a 50% chance of being given a random nature as usual, including the lead Pokémon's nature.  This does not work on Pokémon received outside of battle or roaming legendaries.","shortEffect":"Copies burns, paralysis, and poison received onto the Pokémon that inflicted them.","flavorText":"Passes on status problems.","gen12Pokemon":[{"id":63,"name":"abra","isHidden":false,"slot":1},{"id":64,"name":"kadabra","isHidden":false,"slot":1},{"id":65,"name":"alakazam","isHidden":false,"slot":1},{"id":151,"name":"mew","isHidden":false,"slot":1},{"id":177,"name":"natu","isHidden":false,"slot":1},{"id":178,"name":"xatu","isHidden":false,"slot":1},{"id":196,"name":"espeon","isHidden":false,"slot":1},{"id":197,"name":"umbreon","isHidden":false,"slot":1}],"isMainSeries":true,"generation":"generation-iii"},
