  "natural-cure": {"id":30,"name":"natural-cure","effect":"This Pokémon is cured of any major status ailment when it is switched out for another Pokémon.\n\nIf this ability is acquired during battle, the Pokémon is cured upon leaving battle before losing the temporary ability.","shortEffect":"Cures any major status ailment upon switching out.","flavorText":"Heals upon switching out.","gen12Pokemon":[{"id":113,"name":"chansey","isHidden":false,"slot":1},{"id":120,"name":"staryu","isHidden":false,"slot":2},{"id":121,"name":"starmie","isHidden":false,"slot":2},{"id":222,"name":"corsola","isHidden":false,"slot":2},{"id":242,"name":"blissey","isHidden":false,"slot":1},{"id":251,"name":"celebi","isHidden":false,"slot":1}],"isMainSeries":true,"generation":"generation-iii"},
  "lightning-rod": {"id":31,"name":"lightning-rod","effect":"All other Pokémon's single-target Electric-type moves are redirected to this Pokémon if it is an eligible target.  Other Pokémon's Electric moves raise this Pokémon's Special Attack one stage, negating any other effect on it, and cannot miss it.\n\nIf the move's intended target also has this ability, the move is not redirected.  When multiple Pokémon with this ability are possible targets for redirection, the move is redirected to the one with the highest Speed stat, or, in the case of a tie, to a random tied Pokémon.  Follow Me takes precedence over this ability.\n\nIf the Pokémon is a Ground-type and thus immune to Electric moves, its immunity prevents the Special Attack boost.","shortEffect":"Redirects single-target Electric moves to this Pokémon where possible.  Absorbs Electric moves, raising Special Attack one stage.","flavorText":"Draws electrical moves.","gen12Pokemon":[{"id":25,"name":"pikachu","isHidden":true,"slot":3},{"id":26,"name":"raichu","isHidden":true,"slot":3},{"id":104,"name":"cubone","isHidden":false,"slot":2},{"id":105,"name":"marowak","isHidden":false,"slot":2},{"id":111,"name":"rhyhorn","isHidden":false,"slot":1},{"id":112,"name":"rhydon","isHidden":false,"slot":1},{"id":118,"name":"goldeen","isHidden":true,"slot":3},{"id":119,"name":"seaking","isHidden":true,"slot":3},{"id":172,"name":"pichu","isHidden":true,"slot":3}],"isMainSeries":true,"generation":"generation-iii"},
  "serene-grace": {"id":32,"name":"serene-grace","effect":"This Pokémon's moves have twice their usual effect chance.\n\nAn effect chance is a move's chance to inflict a status ailment, cause a stat change, or make the target flinch in addition to the move's main effect.  For example, Flamethrower's chance of burning the target is doubled, but Protect's chance of success and Air Cutter's increased critical hit rate are unaffected.\n\nSecret Power is unaffected.","shortEffect":"Doubles the chance of moves' extra effects occurring.","flavorText":"Promotes added effects.","gen12Pokemon":[{"id":113,"name":"chansey","isHidden":false,"slot":2},{"id":175,"name":"togepi","isHidden":false,"slot":2},{"id":176,"name":"togetic","isHidden":false,"slot":2},{"id":206,"name":"dunsparce","isHidden":false,"slot":1},{"id":242,"name":"blissey","isHidden":false,"slot":2}],"isMainSeries":true,"generation":"generation-iii"},
