  "chlorophyll": {"id":34,"name":"chlorophyll","effect":"This Pokémon's Speed is doubled during strong sunlight.\n\nThis bonus does not count as a stat modifier.","shortEffect":"Doubles Speed during strong sunlight.","flavorText":"Raises SPEED in sunshine.","gen12Pokemon":[{"id":1,"name":"bulbasaur","isHidden":true,"slot":3},{"id":2,"name":"ivysaur","isHidden":true,"slot":3},{"id":3,"name":"venusaur","isHidden":true,"slot":3},{"id":43,"name":"oddish","isHidden":false,"slot":1},{"id":44,"name":"gloom","isHidden":false,"slot":1},{"id":45,"name":"vileplume","isHidden":false,"slot":1},{"id":69,"name":"bellsprout","isHidden":false,"slot":1},{"id":70,"name":"weepinbell","isHidden":false,"slot":1},{"id":71,"name":"victreebel","isHidden":false,"slot":1},{"id":102,"name":"exeggcute","isHidden":false,"slot":1},{"id":103,"name":"exeggutor","isHidden":false,"slot":1},{"id":114,"name":"tangela","isHidden":false,"slot":1},{"id":182,"name":"bellossom","isHidden":false,"slot":1},{"id":187,"name":"hoppip","isHidden":false,"slot":1},{"id":188,"name":"skiploom","isHidden":false,"slot":1},{"id":189,"name":"jumpluff","isHidden":false,"slot":1},{"id":191,"name":"sunkern","isHidden":false,"slot":1},{"id":192,"name":"sunflora","isHidden":false,"slot":1}],"isMainSeries":true,"generation":"generation-iii"},
