  "pickpocket": {"id":124,"name":"pickpocket","effect":"Whenever a move makes contact with this Pokémon, if it does not have a held item, it steals the attacker's held item.\n\nThis Pokémon cannot steal upon being knocked out.  It can steal if the attacker has a Substitute, but cannot steal when its own Substitute is hit.  If a move hits multiple times, only the last hit triggers this ability.  If this Pokémon is wild, it cannot steal from a trained Pokémon.","shortEffect":"Steals attacking Pokémon's held items on contact.","flavorText":"Steals an item when hit by another Pokémon.","gen12Pokemon":[{"id":215,"name":"sneasel","isHidden":true,"slot":3}],"isMainSeries":true,"generation":"generation-v"},
  "sheer-force": {"id":125,"name":"sheer-force","effect":"This Pokémon's moves with extra effects have 1.3× their power, but lose their extra effects.\n\nAn effect chance is a move's chance to inflict a status ailment, cause a stat change, or make the target flinch in addition to the move's main effect. For example, Thunder Shock's paralysis is an extra effect, but Thunder Wave's is not, nor are Knock Off's item removal and Air Cutter's increased critical hit rate.\n\nMoves that lower the user's stats are unaffected.","shortEffect":"Strengthens moves with extra effects to 1.3× their power, but prevents their extra effects.","flavorText":"Removes added effects to increase move damage.","gen12Pokemon":[{"id":31,"name":"nidoqueen","isHidden":true,"slot":3},{"id":34,"name":"nidoking","isHidden":true,"slot":3},{"id":98,"name":"krabby","isHidden":true,"slot":3},{"id":99,"name":"kingler","isHidden":true,"slot":3},{"id":128,"name":"tauros","isHidden":true,"slot":3},{"id":158,"name":"totodile","isHidden":true,"slot":3},{"id":159,"name":"croconaw","isHidden":true,"slot":3},{"id":160,"name":"feraligatr","isHidden":true,"slot":3},{"id":208,"name":"steelix","isHidden":true,"slot":3}],"isMainSeries":true,"generation":"generation-v"},
