/**
 * Convenience lookup: given a Pokémon ID (1–251), return all its abilities.
 */
export function getAbilitiesForPokemon(pokemonId: number): AbilityEntry[] {
  return Object.values(ABILITIES).filter((ability) =>
    ability.gen12Pokemon.some((p) => p.id === pokemonId),
  );
}
